const ingredients = read('ingredients', []);
const products = read('products', []);
const recipes = read('recipes', []);
const counters = read('counters', {});

// 1. Сырьё
let addIng = 0;
const ingByName = {};
ingredients.forEach(i => ingByName[norm(i.name)] = i);
for (const src of D.ingredients) {
  const n = norm(src.name);
  if (ingByName[n]) { if (!ingByName[n].price && src.price) ingByName[n].price = src.price; continue; }
  const i = { id: genId(), name: src.name, unit: src.unit, price: src.price, active: true, created_at: new Date().toISOString() };
  ingredients.push(i); ingByName[n] = i; addIng++;
}

// 2. Каталог готовой продукции (ПФ в каталог не идут)
const semiSet = new Set(D.semis);
let addProd = 0;
const prodByName = {};
products.forEach(p => prodByName[norm(p.name)] = p);
for (const r of D.recipes) {
  const n = norm(r.name);
  if (semiSet.has(n)) continue;
  if (prodByName[n]) { if (!prodByName[n].category || prodByName[n].category === 'Прочее') prodByName[n].category = D.cat_map[n] || 'Прочее'; continue; }
  counters.product = (counters.product || 0) + 1;
  const p = { id: genId(), name: r.name, category: D.cat_map[n] || 'Прочее', code: 'P' + String(counters.product).padStart(4, '0'), sale_price: 0, active: true };
  products.push(p); prodByName[n] = p; addProd++;
}

// 3. Рецепты: сначала ПФ, затем готовые (чтобы ссылки на ПФ находились)
const recByName = {};
recipes.forEach(r => recByName[norm(r.name)] = r);
const recNames = new Set(D.recipes.map(r => norm(r.name)));
let addRec = 0, skipped = [];
function buildItems(src) {
  const items = [];
  for (const it of src.items) {
    const n = norm(it.name);
    if (recNames.has(n)) {
      const sub = recByName[n];
      if (!sub) return null; // ПФ ещё не создан — отложим
      items.push({ type: 'recipe', ref_id: sub.id, qty: it.qty });
    } else {
      const ing = ingByName[n];
      if (!ing) continue;
      items.push({ type: 'ingredient', ref_id: ing.id, qty: it.qty });
    }
  }
  return items;
}
let queue = D.recipes.slice().sort((a, b) => (semiSet.has(norm(a.name)) ? 0 : 1) - (semiSet.has(norm(b.name)) ? 0 : 1));
for (let pass = 0; pass < 5; pass++) {
  const rest = [];
  for (const src of queue) {
    const n = norm(src.name);
    if (recByName[n]) continue;
    const items = buildItems(src);
    if (items === null) { rest.push(src); continue; }
    if (!items.length) { skipped.push(src.name); continue; }
    const isSemi = semiSet.has(n);
    const rec = { id: genId(), name: src.name, product_id: isSemi ? null : (prodByName[n] ? prodByName[n].id : null),
      is_semifinished: isSemi, output_qty: 1, items, author: 'Импорт калькуляции 2026', created_at: new Date().toISOString() };
    recipes.push(rec); recByName[n] = rec; addRec++;
  }
  queue = rest;
  if (!queue.length) break;
}
queue.forEach(q => skipped.push(q.name + ' (цикл ПФ)'));

write('ingredients', ingredients); write('products', products); write('recipes', recipes); write('counters', counters);
console.log('Сырьё: +' + addIng + ' (всего ' + ingredients.length + ')');
console.log('Каталог: +' + addProd + ' (всего ' + products.length + ')');
console.log('Рецепты: +' + addRec + ' (всего ' + recipes.length + ')');
if (skipped.length) console.log('Пропущено: ' + skipped.join('; '));
console.log('Готово. Цены продажи по новым позициям = 0 — установить в «Цены и маржа».');
